import{_ as a,c as n,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Revisión de planes: Revisar visualmente planes de IA | Plannotator","description":"Aprende la función de revisión de planes de Plannotator. Usa la interfaz visual para revisar planes generados por IA, añade anotaciones para aprobar o rechazar, y domina la diferencia entre Approve y Request Changes.","frontmatter":{"title":"Revisión de planes: Revisar visualmente planes de IA | Plannotator","subtitle":"Fundamentos de revisión de planes: Revisar visualmente planes de IA","description":"Aprende la función de revisión de planes de Plannotator. Usa la interfaz visual para revisar planes generados por IA, añade anotaciones para aprobar o rechazar, y domina la diferencia entre Approve y Request Changes.","sidebarTitle":"Aprende a revisar planes en 5 min","tags":["Revisión de planes","Revisión visual","Anotaciones","Aprobar","Rechazar","Claude Code","OpenCode"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"es/backnotprop/plannotator/platforms/plan-review-basics/index.md","filePath":"es/backnotprop/plannotator/platforms/plan-review-basics/index.md"}'),t={name:"es/backnotprop/plannotator/platforms/plan-review-basics/index.md"};function l(i,e,r,p,c,d){return o(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="fundamentos-de-revision-de-planes-revisar-visualmente-planes-de-ia" tabindex="-1">Fundamentos de revisión de planes: Revisar visualmente planes de IA <a class="header-anchor" href="#fundamentos-de-revision-de-planes-revisar-visualmente-planes-de-ia" aria-label="Permalink to &quot;Fundamentos de revisión de planes: Revisar visualmente planes de IA&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>✅ Usar la interfaz visual de Plannotator para revisar planes generados por IA</li><li>✅ Seleccionar texto del plan y añadir diferentes tipos de anotaciones (eliminar, reemplazar, comentar)</li><li>✅ Aprobar planes para que la IA continúe con la implementación</li><li>✅ Rechazar planes y enviar anotaciones como retroalimentación a la IA</li><li>✅ Comprender los casos de uso y diferencias entre tipos de anotaciones</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p><strong>Problema 1</strong>: Los planes de implementación generados por IA son difíciles de leer en la terminal—demasiado texto, estructura poco clara, revisar es agotador.</p><p><strong>Problema 2</strong>: Cuando quieres dar retroalimentación a la IA, solo puedes describir con texto &quot;elimina el párrafo 3&quot;, &quot;modifica esta función&quot;—alto costo de comunicación, y la IA puede malinterpretar.</p><p><strong>Problema 3</strong>: Algunas partes del plan no necesitan cambios, otras necesitan reemplazo, otras necesitan comentarios, pero no tienes herramientas para estructurar esta retroalimentación.</p><p><strong>Problema 4</strong>: No sabes cómo comunicar a la IA si aprobaste el plan o si necesita modificaciones.</p><p><strong>Plannotator te ayuda</strong>:</p><ul><li>Interfaz visual en lugar de lectura en terminal, estructura clara</li><li>Selecciona texto para añadir anotaciones (eliminar, reemplazar, comentar), retroalimentación precisa</li><li>Las anotaciones se convierten automáticamente en datos estructurados, la IA entiende tu intención con precisión</li><li>Aprueba o rechaza con un clic, la IA responde inmediatamente</li></ul><h2 id="cuando-usar-esto" tabindex="-1">Cuándo usar esto <a class="header-anchor" href="#cuando-usar-esto" aria-label="Permalink to &quot;Cuándo usar esto&quot;">​</a></h2><p><strong>Casos de uso</strong>:</p><ul><li>El AI Agent completa un plan y llama a <code>ExitPlanMode</code> (Claude Code)</li><li>El AI Agent llama a la herramienta <code>submit_plan</code> (OpenCode)</li><li>Necesitas revisar un plan de implementación generado por IA</li><li>Necesitas dar retroalimentación precisa sobre modificaciones al plan</li></ul><p><strong>Casos no aplicables</strong>:</p><ul><li>Dejar que la IA implemente código directamente (saltando la revisión del plan)</li><li>Ya aprobaste el plan y necesitas revisar los cambios de código reales (usa la función de revisión de código)</li></ul><h2 id="🎒-antes-de-empezar" tabindex="-1">🎒 Antes de empezar <a class="header-anchor" href="#🎒-antes-de-empezar" aria-label="Permalink to &quot;🎒 Antes de empezar&quot;">​</a></h2><p><strong>Requisitos previos</strong>:</p><ul><li>✅ Tener instalado Plannotator CLI (ver <a href="./../start/getting-started/">Inicio rápido</a>)</li><li>✅ Tener configurado el plugin de Claude Code u OpenCode (ver la guía de instalación correspondiente)</li><li>✅ El AI Agent soporta revisión de planes (Claude Code 2.1.7+ u OpenCode)</li></ul><p><strong>Cómo activarlo</strong>:</p><ul><li><strong>Claude Code</strong>: Después de que la IA completa el plan, llama automáticamente a <code>ExitPlanMode</code>, Plannotator se inicia automáticamente</li><li><strong>OpenCode</strong>: La IA llama a la herramienta <code>submit_plan</code>, Plannotator se inicia automáticamente</li></ul><h2 id="concepto-principal" tabindex="-1">Concepto principal <a class="header-anchor" href="#concepto-principal" aria-label="Permalink to &quot;Concepto principal&quot;">​</a></h2><h3 id="que-es-la-revision-de-planes" tabindex="-1">Qué es la revisión de planes <a class="header-anchor" href="#que-es-la-revision-de-planes" aria-label="Permalink to &quot;Qué es la revisión de planes&quot;">​</a></h3><p><strong>La revisión de planes</strong> es la función principal de Plannotator, usada para revisar visualmente los planes de implementación generados por IA.</p><div class="info custom-block"><p class="custom-block-title">¿Por qué necesitas revisión de planes?</p><p>Después de que la IA genera un plan, normalmente pregunta &quot;¿Este plan está bien?&quot; o &quot;¿Empiezo la implementación?&quot;. Sin herramientas visuales, solo puedes leer el plan en texto plano en la terminal, y luego responder con retroalimentación vaga como &quot;sí&quot;, &quot;no, modifica XX&quot;. Plannotator te permite ver el plan en una interfaz visual, seleccionar con precisión las partes que necesitan modificación, añadir anotaciones estructuradas, y la IA entiende tu intención más fácilmente.</p></div><h3 id="flujo-de-trabajo" tabindex="-1">Flujo de trabajo <a class="header-anchor" href="#flujo-de-trabajo" aria-label="Permalink to &quot;Flujo de trabajo&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (genera plan) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ ExitPlanMode / submit_plan</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│ Plannotator UI  │  ← El navegador se abre automáticamente</span></span>
<span class="line"><span>│                 │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Contenido  │  │</span></span>
<span class="line"><span>│ │ del plan   │  │</span></span>
<span class="line"><span>│ │ (Markdown) │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       │ Seleccionar texto</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Añadir     │  │</span></span>
<span class="line"><span>│ │ anotación  │  │</span></span>
<span class="line"><span>│ │ Delete/    │  │</span></span>
<span class="line"><span>│ │ Replace/   │  │</span></span>
<span class="line"><span>│ │ Comment    │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>│       │         │</span></span>
<span class="line"><span>│       ▼         │</span></span>
<span class="line"><span>│ ┌───────────┐  │</span></span>
<span class="line"><span>│ │ Decisión   │  │</span></span>
<span class="line"><span>│ │ Approve/  │  │</span></span>
<span class="line"><span>│ │ Request   │  │</span></span>
<span class="line"><span>│ │ Changes   │  │</span></span>
<span class="line"><span>│ └───────────┘  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;allow&quot;} o</span></span>
<span class="line"><span>         │ {&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (continúa     │</span></span>
<span class="line"><span>│  implementación)│</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><h3 id="tipos-de-anotaciones" tabindex="-1">Tipos de anotaciones <a class="header-anchor" href="#tipos-de-anotaciones" aria-label="Permalink to &quot;Tipos de anotaciones&quot;">​</a></h3><p>Plannotator soporta cuatro tipos de anotaciones, cada una con un propósito diferente:</p><table tabindex="0"><thead><tr><th>Tipo de anotación</th><th>Propósito</th><th>Retroalimentación que recibe la IA</th></tr></thead><tbody><tr><td><strong>Delete</strong></td><td>Eliminar contenido innecesario</td><td>&quot;Eliminar: [texto seleccionado]&quot;</td></tr><tr><td><strong>Replace</strong></td><td>Reemplazar con mejor contenido</td><td>&quot;Reemplazar: [texto seleccionado] por [tu texto]&quot;</td></tr><tr><td><strong>Comment</strong></td><td>Comentar una sección, sin requerir cambios</td><td>&quot;Comentario: [texto seleccionado]. Nota: [tu comentario]&quot;</td></tr><tr><td><strong>Global Comment</strong></td><td>Comentario global, no asociado a texto específico</td><td>&quot;Comentario global: [tu comentario]&quot;</td></tr></tbody></table><h3 id="approve-vs-request-changes" tabindex="-1">Approve vs Request Changes <a class="header-anchor" href="#approve-vs-request-changes" aria-label="Permalink to &quot;Approve vs Request Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tipo de decisión</th><th>Acción</th><th>Retroalimentación que recibe la IA</th><th>Caso de uso</th></tr></thead><tbody><tr><td><strong>Approve</strong></td><td>Clic en botón Approve</td><td><code>{&quot;behavior&quot;: &quot;allow&quot;}</code></td><td>El plan está bien, aprobar directamente</td></tr><tr><td><strong>Request Changes</strong></td><td>Clic en botón Request Changes</td><td><code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></td><td>Hay partes que necesitan modificación</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Diferencias entre Claude Code y OpenCode</p><ul><li><strong>Claude Code</strong>: Al aprobar no se envían anotaciones (las anotaciones se ignoran)</li><li><strong>OpenCode</strong>: Al aprobar se pueden enviar anotaciones como notas (opcional)</li></ul><p><strong>Al rechazar el plan</strong>: En ambas plataformas, las anotaciones se envían a la IA</p></div><h2 id="paso-a-paso" tabindex="-1">Paso a paso <a class="header-anchor" href="#paso-a-paso" aria-label="Permalink to &quot;Paso a paso&quot;">​</a></h2><h3 id="paso-1-activar-la-revision-de-planes" tabindex="-1">Paso 1: Activar la revisión de planes <a class="header-anchor" href="#paso-1-activar-la-revision-de-planes" aria-label="Permalink to &quot;Paso 1: Activar la revisión de planes&quot;">​</a></h3><p><strong>Ejemplo con Claude Code</strong>:</p><p>En Claude Code, conversa con la IA para que genere un plan de implementación:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Usuario: Ayúdame a escribir un plan de implementación para un módulo de autenticación de usuarios</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: De acuerdo, aquí está el plan de implementación:</span></span>
<span class="line"><span>1. Crear modelo de usuario</span></span>
<span class="line"><span>2. Implementar API de registro</span></span>
<span class="line"><span>3. Implementar API de inicio de sesión</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(La IA llama a ExitPlanMode)</span></span></code></pre></div><p><strong>Ejemplo con OpenCode</strong>:</p><p>En OpenCode, la IA llama automáticamente a la herramienta <code>submit_plan</code>.</p><p><strong>Deberías ver</strong>:</p><ol><li>El navegador se abre automáticamente con la UI de Plannotator</li><li>Se muestra el contenido del plan generado por la IA (formato Markdown)</li><li>En la parte inferior de la página hay botones &quot;Approve&quot; y &quot;Request Changes&quot;</li></ol><h3 id="paso-2-revisar-el-contenido-del-plan" tabindex="-1">Paso 2: Revisar el contenido del plan <a class="header-anchor" href="#paso-2-revisar-el-contenido-del-plan" aria-label="Permalink to &quot;Paso 2: Revisar el contenido del plan&quot;">​</a></h3><p>Revisa el plan en el navegador:</p><ul><li>El plan se renderiza en formato Markdown, incluyendo títulos, párrafos, listas, bloques de código</li><li>Puedes desplazarte para ver todo el plan</li><li>Soporta cambio de modo claro/oscuro (clic en el botón de cambio de tema en la esquina superior derecha)</li></ul><h3 id="paso-3-seleccionar-texto-del-plan-y-anadir-anotaciones" tabindex="-1">Paso 3: Seleccionar texto del plan y añadir anotaciones <a class="header-anchor" href="#paso-3-seleccionar-texto-del-plan-y-anadir-anotaciones" aria-label="Permalink to &quot;Paso 3: Seleccionar texto del plan y añadir anotaciones&quot;">​</a></h3><p><strong>Añadir anotación Delete</strong>:</p><ol><li>Selecciona con el ratón el texto que necesitas eliminar del plan</li><li>En la barra de herramientas emergente, haz clic en el botón <strong>Delete</strong></li><li>El texto se marcará con estilo de eliminación (tachado rojo)</li></ol><p><strong>Añadir anotación Replace</strong>:</p><ol><li>Selecciona con el ratón el texto que necesitas reemplazar del plan</li><li>En la barra de herramientas emergente, haz clic en el botón <strong>Replace</strong></li><li>En el cuadro de entrada emergente, escribe el contenido de reemplazo</li><li>Presiona Enter o haz clic en confirmar</li><li>El texto original se marcará con estilo de reemplazo (fondo amarillo), y el contenido de reemplazo se mostrará debajo</li></ol><p><strong>Añadir anotación Comment</strong>:</p><ol><li>Selecciona con el ratón el texto que necesitas comentar del plan</li><li>En la barra de herramientas emergente, haz clic en el botón <strong>Comment</strong></li><li>En el cuadro de entrada emergente, escribe el contenido del comentario</li><li>Presiona Enter o haz clic en confirmar</li><li>El texto se marcará con estilo de comentario (resaltado azul), y el comentario se mostrará en la barra lateral</li></ol><p><strong>Añadir Global Comment</strong>:</p><ol><li>Haz clic en el botón <strong>Add Global Comment</strong> en la esquina superior derecha de la página</li><li>En el cuadro de entrada emergente, escribe el contenido del comentario global</li><li>Presiona Enter o haz clic en confirmar</li><li>El comentario se mostrará en la sección &quot;Global Comments&quot; de la barra lateral</li></ol><p><strong>Deberías ver</strong>:</p><ul><li>Después de seleccionar texto, aparece inmediatamente una barra de herramientas (Delete, Replace, Comment)</li><li>Después de añadir anotaciones, el texto muestra el estilo correspondiente (tachado, color de fondo, resaltado)</li><li>La barra lateral muestra la lista de todas las anotaciones, puedes hacer clic para saltar a la posición correspondiente</li><li>Puedes hacer clic en el botón <strong>eliminar</strong> junto a la anotación para quitarla</li></ul><h3 id="paso-4-aprobar-el-plan" tabindex="-1">Paso 4: Aprobar el plan <a class="header-anchor" href="#paso-4-aprobar-el-plan" aria-label="Permalink to &quot;Paso 4: Aprobar el plan&quot;">​</a></h3><p><strong>Si el plan no tiene problemas</strong>:</p><p>Haz clic en el botón <strong>Approve</strong> en la parte inferior de la página.</p><p><strong>Deberías ver</strong>:</p><ul><li>El navegador se cierra automáticamente (retraso de 1.5 segundos)</li><li>La terminal de Claude Code/OpenCode muestra que el plan fue aprobado</li><li>La IA continúa implementando el plan</li></ul><div class="info custom-block"><p class="custom-block-title">Comportamiento de Approve</p><ul><li><strong>Claude Code</strong>: Solo envía <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, las anotaciones se ignoran</li><li><strong>OpenCode</strong>: Envía <code>{&quot;behavior&quot;: &quot;allow&quot;}</code>, las anotaciones pueden enviarse como notas (opcional)</li></ul></div><h3 id="paso-5-rechazar-el-plan-request-changes" tabindex="-1">Paso 5: Rechazar el plan (Request Changes) <a class="header-anchor" href="#paso-5-rechazar-el-plan-request-changes" aria-label="Permalink to &quot;Paso 5: Rechazar el plan (Request Changes)&quot;">​</a></h3><p><strong>Si el plan necesita modificaciones</strong>:</p><ol><li>Añade las anotaciones necesarias (Delete, Replace, Comment)</li><li>Haz clic en el botón <strong>Request Changes</strong> en la parte inferior de la página</li><li>El navegador mostrará un diálogo de confirmación</li></ol><p><strong>Deberías ver</strong>:</p><ul><li>El diálogo de confirmación muestra &quot;Send X annotations to AI?&quot;</li><li>Después de confirmar, el navegador se cierra automáticamente</li><li>La terminal de Claude Code/OpenCode muestra el contenido de la retroalimentación</li><li>La IA modificará el plan según la retroalimentación</li></ul><div class="tip custom-block"><p class="custom-block-title">Comportamiento de Request Changes</p><ul><li><strong>Claude Code</strong> y <strong>OpenCode</strong>: Ambos envían <code>{&quot;behavior&quot;: &quot;deny&quot;, &quot;message&quot;: &quot;...&quot;}</code></li><li>Las anotaciones se convierten en texto Markdown estructurado</li><li>La IA modificará el plan y llamará nuevamente a ExitPlanMode/submit_plan</li></ul></div><h3 id="paso-6-ver-el-contenido-de-la-retroalimentacion-opcional" tabindex="-1">Paso 6: Ver el contenido de la retroalimentación (opcional) <a class="header-anchor" href="#paso-6-ver-el-contenido-de-la-retroalimentacion-opcional" aria-label="Permalink to &quot;Paso 6: Ver el contenido de la retroalimentación (opcional)&quot;">​</a></h3><p>Si quieres ver el contenido de la retroalimentación que Plannotator envía a la IA, puedes verlo en la terminal:</p><p><strong>Claude Code</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan rejected by user</span></span>
<span class="line"><span>Please modify the plan based on the following feedback:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[contenido estructurado de las anotaciones]</span></span></code></pre></div><p><strong>OpenCode</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;feedback&gt;</span></span>
<span class="line"><span>[contenido estructurado de las anotaciones]</span></span>
<span class="line"><span>&lt;/feedback&gt;</span></span></code></pre></div><h2 id="punto-de-verificacion-✅" tabindex="-1">Punto de verificación ✅ <a class="header-anchor" href="#punto-de-verificacion-✅" aria-label="Permalink to &quot;Punto de verificación ✅&quot;">​</a></h2><p>Después de completar los pasos anteriores, deberías poder:</p><ul><li>[ ] Después de que la IA active la revisión de planes, el navegador abre automáticamente la UI de Plannotator</li><li>[ ] Seleccionar texto del plan y añadir anotaciones Delete, Replace, Comment</li><li>[ ] Añadir Global Comment</li><li>[ ] Ver todas las anotaciones en la barra lateral y saltar a la posición correspondiente</li><li>[ ] Hacer clic en Approve, el navegador se cierra, la IA continúa implementando</li><li>[ ] Hacer clic en Request Changes, el navegador se cierra, la IA modifica el plan</li></ul><p><strong>Si algún paso falla</strong>, consulta:</p><ul><li><a href="./../../faq/common-problems/">Preguntas frecuentes</a></li><li><a href="./../../start/installation-claude-code/">Guía de instalación de Claude Code</a></li><li><a href="./../../start/installation-opencode/">Guía de instalación de OpenCode</a></li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><p><strong>Error común 1</strong>: Después de seleccionar texto, la barra de herramientas no aparece</p><p><strong>Causa</strong>: Puede ser porque seleccionaste texto dentro de un bloque de código, o el texto seleccionado cruza múltiples elementos.</p><p><strong>Solución</strong>:</p><ul><li>Intenta seleccionar texto dentro de un solo párrafo o elemento de lista</li><li>Para bloques de código, puedes usar anotación Comment, no selecciones múltiples líneas</li></ul><p><strong>Error común 2</strong>: Después de añadir anotación Replace, el contenido de reemplazo no se muestra</p><p><strong>Causa</strong>: El cuadro de entrada del contenido de reemplazo puede no haberse enviado correctamente.</p><p><strong>Solución</strong>:</p><ul><li>Después de escribir el contenido de reemplazo, presiona Enter o haz clic en el botón de confirmar</li><li>Verifica si el contenido de reemplazo se muestra en la barra lateral</li></ul><p><strong>Error común 3</strong>: Después de hacer clic en Approve o Request Changes, el navegador no se cierra</p><p><strong>Causa</strong>: Puede ser un error del servidor o problema de red.</p><p><strong>Solución</strong>:</p><ul><li>Verifica si hay mensajes de error en la terminal</li><li>Cierra el navegador manualmente</li><li>Si el problema persiste, consulta <a href="./../../faq/troubleshooting/">Solución de problemas</a></li></ul><p><strong>Error común 4</strong>: La IA recibe la retroalimentación pero no modifica según las anotaciones</p><p><strong>Causa</strong>: La IA puede no haber entendido correctamente la intención de las anotaciones.</p><p><strong>Solución</strong>:</p><ul><li>Intenta usar anotaciones más explícitas (Replace es más explícito que Comment)</li><li>Usa Comment para añadir explicaciones detalladas</li><li>Si el problema persiste, puedes rechazar el plan nuevamente y ajustar el contenido de las anotaciones</li></ul><p><strong>Error común 5</strong>: Después de añadir múltiples anotaciones Delete, la IA solo eliminó parte del contenido</p><p><strong>Causa</strong>: Puede haber superposición o conflicto entre múltiples anotaciones Delete.</p><p><strong>Solución</strong>:</p><ul><li>Asegúrate de que el rango de texto de cada anotación Delete no se superponga</li><li>Si necesitas eliminar una sección grande, selecciona todo el párrafo y elimínalo de una vez</li></ul><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><p>La revisión de planes es la función principal de Plannotator, permitiéndote revisar visualmente los planes generados por IA:</p><p><strong>Operaciones principales</strong>:</p><ol><li><strong>Activar</strong>: La IA llama a <code>ExitPlanMode</code> o <code>submit_plan</code>, el navegador abre automáticamente la UI</li><li><strong>Revisar</strong>: Ver el contenido del plan en la interfaz visual (formato Markdown)</li><li><strong>Anotar</strong>: Seleccionar texto, añadir Delete, Replace, Comment o Global Comment</li><li><strong>Decidir</strong>: Hacer clic en Approve (aprobar) o Request Changes (rechazar)</li><li><strong>Retroalimentación</strong>: Las anotaciones se convierten en datos estructurados, la IA continúa o modifica el plan según la retroalimentación</li></ol><p><strong>Tipos de anotaciones</strong>:</p><ul><li><strong>Delete</strong>: Eliminar contenido innecesario</li><li><strong>Replace</strong>: Reemplazar con mejor contenido</li><li><strong>Comment</strong>: Comentar una sección, sin requerir cambios</li><li><strong>Global Comment</strong>: Comentario global, no asociado a texto específico</li></ul><p><strong>Tipos de decisión</strong>:</p><ul><li><strong>Approve</strong>: El plan está bien, aprobar directamente (Claude Code ignora las anotaciones)</li><li><strong>Request Changes</strong>: Hay partes que necesitan modificación, las anotaciones se envían a la IA</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../plan-review-annotations/">Añadir anotaciones al plan</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo usar con precisión las anotaciones Delete, Replace, Comment</li><li>Cómo añadir anotaciones de imagen</li><li>Cómo editar y eliminar anotaciones</li><li>Mejores prácticas y escenarios comunes de anotaciones</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver la ubicación del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>UI de revisión de planes</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Definición de tipos de anotación</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/types.ts#L1-L70" target="_blank" rel="noreferrer"><code>packages/ui/types.ts</code></a></td><td>1-70</td></tr><tr><td>Servidor de revisión de planes</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L91-L310" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>91-310</td></tr><tr><td>API: Obtener contenido del plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L132-L134" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>132-134</td></tr><tr><td>API: Aprobar plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L201-L277" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>201-277</td></tr><tr><td>API: Rechazar plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L280-L309" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>280-309</td></tr><tr><td>Componente Viewer</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L1-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></td><td>1-100</td></tr><tr><td>Componente AnnotationPanel</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a></td><td>1-50</td></tr></tbody></table><p><strong>Tipos clave</strong>:</p><ul><li><code>AnnotationType</code>: Enumeración de tipos de anotación (DELETION, INSERTION, REPLACEMENT, COMMENT, GLOBAL_COMMENT) (<code>packages/ui/types.ts:1-7</code>)</li><li><code>Annotation</code>: Interfaz de anotación (<code>packages/ui/types.ts:11-33</code>)</li><li><code>Block</code>: Interfaz de bloque de plan (<code>packages/ui/types.ts:35-44</code>)</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Inicia el servidor de revisión de planes (<code>packages/server/index.ts:91</code>)</li><li><code>parseMarkdownToBlocks()</code>: Parsea Markdown a Blocks (<code>packages/ui/utils/parser.ts</code>)</li></ul><p><strong>Rutas de API</strong>:</p><ul><li><code>GET /api/plan</code>: Obtener contenido del plan (<code>packages/server/index.ts:132</code>)</li><li><code>POST /api/approve</code>: Aprobar plan (<code>packages/server/index.ts:201</code>)</li><li><code>POST /api/deny</code>: Rechazar plan (<code>packages/server/index.ts:280</code>)</li></ul><p><strong>Reglas de negocio</strong>:</p><ul><li>Claude Code no envía anotaciones al aprobar (<code>apps/hook/server/index.ts:132</code>)</li><li>OpenCode puede enviar anotaciones como notas al aprobar (<code>apps/opencode-plugin/index.ts:270</code>)</li><li>Al rechazar el plan, las anotaciones siempre se envían (<code>apps/hook/server/index.ts:154</code>)</li></ul></details>`,112)])])}const g=a(t,[["render",l]]);export{m as __pageData,g as default};
